class Solution {
    public List<Long> maximumEvenSplit(long finalSum) {
        if (finalSum % 2 != 0 || finalSum == 2) {
            return new ArrayList<>();
        }
        List<Long> result = new ArrayList<>();
        long current = 2;
        while (finalSum > 0) {
            if (finalSum - current >= current) {
                finalSum -= current;
                result.add(current);
            } else {
                current += 2;
            }
        }
        return result;
    }
}
